async function loadPPMP() {
  const tbody = document.getElementById('ppmpTableBody');
  try {
    const chiefRoles = ['chief_fad', 'chief_wrsd', 'chief_mwpsd', 'chief_mwptd'];
    const isChief = userHasAnyRole(chiefRoles);
    const isPPMPEncoder = userHasRole('ppmp_encoder');

    // Check if user has multi-division PPMP access
    const hasMultiDivAccess = currentUser.managed_dept_ids && currentUser.managed_dept_ids.length > 1;

    // === SPECIAL USER ACCESS CONTROL ===
    // REGIENALD S. ESPALDON: access all pending PPMP except WRSD (dept_id=4)
    // EVAL B. MAKINANO: access and approve ALL pending entries
    // ANNE JANE M. HALLASGO: WRSD PPMP encoder (dept_id=4)
    const userName = (currentUser.full_name || '').toUpperCase();
    const isEspaldon = userName.includes('ESPALDON');
    const isMakinano = userName.includes('MAKINANO');
    const isHallasgo = userName.includes('HALLASGO');

    // Roles that can see ALL divisions' PPMP data (chiefs are NOT included - they only see their division)
    const seeAllPPMPRoles = ['admin', 'hope', 'ord_manager', 'bac_secretariat', 'budget_consultant'];
    // Chiefs should be locked to their division UNLESS they have special cross-division access
    const hasSpecialAccess = isEspaldon || isMakinano;
    const canSeeAll = userHasAnyRole(seeAllPPMPRoles) || hasSpecialAccess;

    // Chiefs are locked to their division unless they have special cross-division access
    const isLockedDivision = (isChief && !hasSpecialAccess) || (!canSeeAll && !hasMultiDivAccess);

    const divFilter = document.getElementById('ppmpDivisionFilter');
    const modeFilter = document.getElementById('ppmpModeFilter');
    const catFilter = document.getElementById('ppmpCategoryFilter');
    const yearFilter = document.getElementById('ppmpYearFilter');
    const searchInput = document.getElementById('ppmpSearchInput');

    // For multi-division users: enable dropdown but restrict options to managed divisions
    if (hasMultiDivAccess && divFilter) {
      divFilter.disabled = false;
      divFilter.style.opacity = '1';
      // Filter dropdown options to only show managed divisions + "All" option
      const managedIds = currentUser.managed_dept_ids.map(String);
      Array.from(divFilter.options).forEach(opt => {
        if (opt.value === '' || opt.value === 'all') {
          opt.style.display = ''; // keep the "All" option visible
        } else {
          opt.style.display = managedIds.includes(opt.value) ? '' : 'none';
        }
      });
    } else if (isLockedDivision && divFilter) {
      if (isChief) {
        const chiefDeptMap = { chief_fad: '1', chief_wrsd: '4', chief_mwpsd: '3', chief_mwptd: '2' };
        const chiefRole = getUserChiefRole();
        divFilter.value = chiefDeptMap[chiefRole] || '';
      } else {
        divFilter.value = currentUser.dept_id ? String(currentUser.dept_id) : '';
      }
      divFilter.disabled = true;
      divFilter.style.opacity = '0.7';
    } else if (divFilter) {
      divFilter.disabled = false;
      divFilter.style.opacity = '1';
    }

    // Read selected division ("all" = all divisions, specific number = one division)
    let selectedDept = divFilter ? divFilter.value : 'all';

    // Enforce division filtering for non-global users even if dropdown didn't set correctly
    if (isLockedDivision && (!selectedDept || selectedDept === 'all')) {
      if (isChief) {
        const chiefDeptMapFallback = { chief_fad: '1', chief_wrsd: '4', chief_mwpsd: '3', chief_mwptd: '2' };
        selectedDept = chiefDeptMapFallback[getUserChiefRole()] || '';
      } else if (currentUser.dept_id) {
        selectedDept = String(currentUser.dept_id);
      }
    }

    // Show loading indicator
    if (tbody) {
      tbody.innerHTML = '<tr><td colspan="15" class="text-center" style="padding:30px;color:#636e78;"><i class="fas fa-spinner fa-spin" style="font-size:20px;margin-right:8px;"></i>Loading PPMP data from database...</td></tr>';
    }

    // Build server query with all filters
    const selectedYear = yearFilter ? yearFilter.value : String(getCurrentFiscalYear());
    const selectedMode = modeFilter ? modeFilter.value : '';
    const sourceFilter = document.getElementById('ppmpSourceFilter');
    const selectedSource = sourceFilter ? sourceFilter.value : '';
    let url = '/ppmp?fiscal_year=' + selectedYear;
    if (selectedDept && selectedDept !== 'all') url += '&dept_id=' + selectedDept;
    if (selectedMode) url += '&procurement_mode=' + encodeURIComponent(selectedMode);
    if (selectedSource) url += '&procurement_source=' + encodeURIComponent(selectedSource);

    // Add cache-busting parameter to ensure fresh data from database
    url += '&_cache_bust=' + Date.now();

    console.log('[PPMP] Fetching fresh data from database: ' + url);
    const ppmp = await apiRequest(url);
    console.log('[PPMP] Fresh data received from database - ' + ppmp.length + ' entries');
    
    // === SPECIAL ACCESS: ESPALDON sees all except WRSD (dept_id=4) ===
    let accessFiltered = ppmp;
    if (isEspaldon) {
      accessFiltered = ppmp.filter(p => p.dept_id !== 4 && (p.department_code || '').toUpperCase() !== 'WRSD');
    }
    // HALLASGO sees only WRSD (dept_id=4) entries
    if (isHallasgo) {
      accessFiltered = ppmp.filter(p => p.dept_id === 4 || (p.department_code || '').toUpperCase() === 'WRSD');
    }

    // Apply client-side text search across ALL visible columns
    const searchText = searchInput ? searchInput.value.trim().toLowerCase() : '';
    const selectedCategory = catFilter ? catFilter.value : '';
    let filtered = accessFiltered;

    // Category filter (also matches section)
    if (selectedCategory) {
      filtered = filtered.filter(p => 
        (p.item_category || p.category || '') === selectedCategory ||
        (p.section || '') === selectedCategory
      );
    }

    if (searchText) {
      filtered = filtered.filter(p =>
        (p.ppmp_no || '').toLowerCase().includes(searchText) ||
        (p.description || '').toLowerCase().includes(searchText) ||
        (p.remarks || '').toLowerCase().includes(searchText) ||
        (p.procurement_mode || '').toLowerCase().includes(searchText) ||
        (p.quantity_size || '').toLowerCase().includes(searchText) ||
        (p.project_type || '').toLowerCase().includes(searchText) ||
        (p.fund_source || '').toLowerCase().includes(searchText) ||
        (p.start_date || '').toLowerCase().includes(searchText) ||
        (p.end_date || '').toLowerCase().includes(searchText) ||
        (p.delivery_period || '').toLowerCase().includes(searchText) ||
        (p.department_code || '').toLowerCase().includes(searchText) ||
        (p.department_name || '').toLowerCase().includes(searchText) ||
        (p.category || '').toLowerCase().includes(searchText) ||
        (p.item_category || '').toLowerCase().includes(searchText) ||
        (p.item_name || '').toLowerCase().includes(searchText) ||
        (p.item_description || '').toLowerCase().includes(searchText) ||
        (p.section || '').toLowerCase().includes(searchText) ||
        (p.status || '').toLowerCase().includes(searchText) ||
        String(p.total_amount || '').includes(searchText)
      );
    }

    // Populate category filter dropdown from loaded data (sections + categories)
    if (catFilter) {
      const currentVal = catFilter.value;
      const sections = [...new Set(accessFiltered.map(p => p.section).filter(Boolean))].sort();
      const cats = [...new Set(accessFiltered.map(p => p.item_category || p.category).filter(Boolean))].sort();
      let optionsHtml = '<option value="">All Sections / Categories</option>';
      if (sections.length > 0) {
        optionsHtml += '<optgroup label="── Sections ──">';
        sections.forEach(s => { optionsHtml += `<option value="${s}" ${s === currentVal ? 'selected' : ''}>${s}</option>`; });
        optionsHtml += '</optgroup>';
      }
      if (cats.length > 0) {
        optionsHtml += '<optgroup label="── Categories ──">';
        cats.forEach(c => { optionsHtml += `<option value="${c}" ${c === currentVal ? 'selected' : ''}>${c}</option>`; });
        optionsHtml += '</optgroup>';
      }
      catFilter.innerHTML = optionsHtml;
    }
    

    // Update division banner
    let banner = document.getElementById('ppmpDivisionBanner');
    if (hasSpecialAccess) {
      // Special cross-division access user
      if (!banner) {
        banner = document.createElement('div');
        banner.id = 'ppmpDivisionBanner';
        banner.className = 'ppmp-division-banner';
        const ppmpSection = document.getElementById('ppmp');
        const pageActions = ppmpSection?.querySelector('.page-actions');
        if (pageActions) {
          pageActions.parentNode.insertBefore(banner, pageActions);
        }
      }
      if (isEspaldon) {
        banner.innerHTML = `<i class="fas fa-building"></i> Showing all PPMP entries <strong>except WRSD</strong>`;
      } else if (isMakinano) {
        banner.innerHTML = `<i class="fas fa-building"></i> Showing <strong>ALL</strong> division PPMP entries (with approval access)`;
      }
      banner.style.display = '';
    } else if (hasMultiDivAccess) {
      // Multi-division user — show banner listing managed divisions
      const managedCodes = cachedDivisions.filter(d => currentUser.managed_dept_ids.map(String).includes(String(d.id))).map(d => d.code || d.name);
      if (!banner) {
        banner = document.createElement('div');
        banner.id = 'ppmpDivisionBanner';
        banner.className = 'ppmp-division-banner';
        const ppmpSection = document.getElementById('ppmp');
        const pageActions = ppmpSection?.querySelector('.page-actions');
        if (pageActions) {
          pageActions.parentNode.insertBefore(banner, pageActions);
        }
      }
      banner.innerHTML = `<i class="fas fa-building"></i> Managing PPMP for: <strong>${managedCodes.join(', ')}</strong>`;
      banner.style.display = '';
    } else if (isLockedDivision) {
      const divName = currentUser.division || currentUser.department_code || '';
      if (!banner) {
        banner = document.createElement('div');
        banner.id = 'ppmpDivisionBanner';
        banner.className = 'ppmp-division-banner';
        const ppmpSection = document.getElementById('ppmp');
        const pageActions = ppmpSection?.querySelector('.page-actions');
        if (pageActions) {
          pageActions.parentNode.insertBefore(banner, pageActions);
        }
      }
      banner.innerHTML = `<i class="fas fa-building"></i> Showing PPMP for <strong>${divName}</strong> Division Only`;
      banner.style.display = '';
    } else if (banner) {
      banner.style.display = 'none';
    }

    // Render the filtered PPMP data to the table
    renderPPMPTable(filtered, ppmp);
    return filtered;
  } catch (err) {
    console.error('Error loading PPMP:', err);
    if (tbody) {
      tbody.innerHTML = '<tr><td colspan="15" class="text-center" style="padding:30px;color:#e53e3e;"><i class="fas fa-exclamation-triangle" style="font-size:20px;margin-right:8px;"></i><strong>Failed to load PPMP data.</strong><br><small>Please check if the server is running and try again.</small><br><button class="btn btn-primary" style="margin-top:10px;" onclick="loadPPMP()"><i class="fas fa-redo"></i> Retry</button></td></tr>';
    }
    return [];
  }
}

// Initialize PPMP filter event listeners (called once after login)
async function initPPMPFilters() {
  const divFilter = document.getElementById('ppmpDivisionFilter');
  const modeFilter = document.getElementById('ppmpModeFilter');
  const yearFilter = document.getElementById('ppmpYearFilter');
  const searchInput = document.getElementById('ppmpSearchInput');
  
  // Populate division filter from DB (await so loadPPMP sees the options)
  if (divFilter && divFilter.options.length <= 1) {
    try {
      const divisions = await apiRequest('/divisions');
      divisions.forEach(d => {
        const opt = document.createElement('option');
        opt.value = d.id;
        opt.textContent = d.code || d.name;
        divFilter.appendChild(opt);
      });
    } catch(e) {}
  }

  // Populate mode filter from DB
  if (modeFilter && modeFilter.options.length <= 1) {
    apiRequest('/procurement-modes').then(modes => {
      modes.forEach(m => {
        const opt = document.createElement('option');
        opt.value = m.name;
        opt.textContent = m.name;
        modeFilter.appendChild(opt);
      });
    }).catch(() => {});
  }

  // Populate PR division filter from DB
  const prDivFilter = document.getElementById('prDivisionFilter');
  if (prDivFilter && prDivFilter.options.length <= 1) {
    apiRequest('/divisions').then(divisions => {
      divisions.forEach(d => {
        const opt = document.createElement('option');
        opt.value = d.code || d.name;
        opt.textContent = d.code || d.name;
        prDivFilter.appendChild(opt);
      });
    }).catch(() => {});
  }

  // Category filter
  const catFilter = document.getElementById('ppmpCategoryFilter');
  if (catFilter) catFilter.onchange = function() { loadPPMP(); };

  // Procurement Source filter (PS-DBM / NON PS-DBM / PAPs)
  const sourceFilter = document.getElementById('ppmpSourceFilter');
  if (sourceFilter) sourceFilter.onchange = function() { loadPPMP(); };

  if (divFilter) divFilter.onchange = function() { loadPPMP(); };
  if (modeFilter) modeFilter.onchange = function() { loadPPMP(); };
  if (yearFilter) yearFilter.onchange = function() { loadPPMP(); };
  if (searchInput) {
    let debounce;
    searchInput.oninput = function() {
      clearTimeout(debounce);
      debounce = setTimeout(() => loadPPMP(), 300);
    };
  }
}

async function loadAPP() {
  try {
    const fy = window._appFilterYear || getCurrentFiscalYear();
    const [items, appStatus, budgetSummary] = await Promise.all([
      apiRequest('/plan-items?fiscal_year=' + fy + '&_cache_bust=' + Date.now()),
      loadAPPStatus(fy),
      apiRequest('/app-budget-summary?fiscal_year=' + fy + '&_cache_bust=' + Date.now())
    ]);
    console.log('[APP] ✅ Fresh data fetched from database');

    // Check if consolidation has been done
    const isConsolidated = appStatus && appStatus.consolidated_at;

    // Check for new unconsolidated entries (approved after last consolidation)
    let newUnconsolidatedCount = 0;
    if (isConsolidated) {
      const consolidatedAt = new Date(appStatus.consolidated_at);
      newUnconsolidatedCount = items.filter(item => {
        const approvedAt = item.updated_at ? new Date(item.updated_at) : null;
        return approvedAt && approvedAt > consolidatedAt;
      }).length;
    }

    // Update consolidate button with badge for new entries
    const consolidateBtn = document.querySelector('[data-action="consolidate-app"]');
    if (consolidateBtn) {
      // Remove old badge if any
      const oldBadge = consolidateBtn.querySelector('.consolidate-badge');
      if (oldBadge) oldBadge.remove();

      if (!isConsolidated) {
        consolidateBtn.innerHTML = '<i class="fas fa-layer-group"></i> Consolidate from PPMP <span class="consolidate-badge" style="background:#ff5722;color:#fff;border-radius:10px;padding:1px 7px;font-size:10px;margin-left:5px;">Not yet consolidated</span>';
      } else if (newUnconsolidatedCount > 0) {
        consolidateBtn.innerHTML = '<i class="fas fa-layer-group"></i> Consolidate from PPMP <span class="consolidate-badge" style="background:#ff9800;color:#fff;border-radius:10px;padding:1px 7px;font-size:10px;margin-left:5px;">' + newUnconsolidatedCount + ' new</span>';
      } else {
        consolidateBtn.innerHTML = '<i class="fas fa-layer-group"></i> Consolidate from PPMP';
      }
    }

    // Only show items if consolidated, otherwise show message
    if (isConsolidated) {
      renderAPPTable(items, appStatus);
      updateAPPSummary(items, budgetSummary);
    } else {
      renderAPPTable([], appStatus);
      updateAPPSummary([], budgetSummary);
      // Show notice
      const tableBody = document.querySelector('#appTableBody, #app-table tbody');
      if (tableBody) {
        tableBody.innerHTML = '<tr><td colspan="10" style="text-align:center;padding:30px;color:#666;font-size:14px;"><i class="fas fa-info-circle" style="font-size:24px;color:#2196f3;margin-bottom:8px;display:block;"></i>No APP entries yet. Click <strong>"Consolidate from PPMP"</strong> to import approved PPMP entries into the Annual Procurement Plan.<br><small style="color:#999;">There are <strong>' + items.length + '</strong> approved PPMP entries ready for consolidation.</small></td></tr>';
      }
    }

    updateAPPVersionBanner(appStatus);
    return isConsolidated ? items : [];
  } catch (err) {
    console.log('Using demo APP data');
    return [];
  }
}

async function loadAPPStatus(year) {
  try {
    // 🔄 FRESH FETCH FROM DATABASE - Cache busting parameter ensures no caching
    const status = await apiRequest('/app-settings/' + year + '?_cache_bust=' + Date.now());
    window._appStatus = status;
    return status;
  } catch (err) {
    console.log('Could not load APP status');
    return { fiscal_year: year, app_type: 'indicative', update_count: 0 };
  }
}

async function loadPR() {
  try {
    // 🔄 FRESH FETCH FROM DATABASE - Cache busting parameter ensures no caching
    const pr = await apiRequest('/pr?_cache_bust=' + Date.now());
    console.log('[PR] ✅ Fresh data fetched from database');
    cachedPR = pr;

    // Chiefs should be locked to their division even if they have other roles
    const chiefRoles = ['chief_fad', 'chief_wrsd', 'chief_mwpsd', 'chief_mwptd'];
    const isChief = userHasAnyRole(chiefRoles);

    // Lock division filter for chiefs and non-global roles
    const seeAllRoles = ['admin', 'hope', 'bac_chair', 'bac_secretariat'];
    const canSeeAll = userHasAnyRole(seeAllRoles) && !isChief;
    const prDivFilter = document.getElementById('prDivisionFilter');
    if (prDivFilter && !canSeeAll) {
      // Auto-select user's division code and disable dropdown
      const chiefDivCodeMap = { chief_fad: 'FAD', chief_wrsd: 'WRSD', chief_mwpsd: 'MWPSD', chief_mwptd: 'MWPTD' };
      const chiefRole = getUserChiefRole();
      const deptCode = chiefRole ? chiefDivCodeMap[chiefRole] : (currentUser.department_code || currentUser.division || '');
      if (deptCode) {
        prDivFilter.value = deptCode;
        prDivFilter.disabled = true;
        prDivFilter.style.opacity = '0.7';
      }
    } else if (prDivFilter) {
      prDivFilter.disabled = false;
      prDivFilter.style.opacity = '1';
    }

    filterPRTable();
    return pr;
  } catch (err) {
    console.log('Using demo PR data');
    return [];
  }
}
function filterPRTable() {
  const statusVal = document.getElementById('prStatusFilter')?.value || '';
  const divVal = document.getElementById('prDivisionFilter')?.value || '';
  let data = cachedPR;

  // Chiefs should be locked to their division even if they have other roles
  const chiefRoles = ['chief_fad', 'chief_wrsd', 'chief_mwpsd', 'chief_mwptd'];
  const isChief = userHasAnyRole(chiefRoles);
  const chiefDivCodeMap = { chief_fad: 'FAD', chief_wrsd: 'WRSD', chief_mwpsd: 'MWPSD', chief_mwptd: 'MWPTD' };
  const chiefRole = getUserChiefRole();

  // Division-based filtering: only admin, hope, bac_chair, bac_secretariat see ALL PRs (unless they're a chief)
  const seeAllRoles = ['admin', 'hope', 'bac_chair', 'bac_secretariat'];
  const canSeeAll = userHasAnyRole(seeAllRoles) && !isChief;

  if (!canSeeAll) {
    // Filter to user's own division only
    const userDeptCode = isChief ? chiefDivCodeMap[chiefRole] : (currentUser.department_code || currentUser.division || '').toUpperCase();
    const userDeptId = currentUser.dept_id;
    if (userDeptCode || userDeptId) {
      data = data.filter(r => {
        const rDeptCode = (r.department_code || '').toUpperCase();
        return rDeptCode === userDeptCode || String(r.dept_id) === String(userDeptId);
      });
    }
  }

  // Draft PRs: admin/hope see all drafts, others only see their own
  if (!userHasAnyRole(['admin', 'hope'])) {
    const userId = currentUser.id;
    data = data.filter(r => r.status !== 'draft' || String(r.requested_by) === String(userId));
  }

  if (statusVal) data = data.filter(r => r.status === statusVal);
  if (divVal) data = data.filter(r => String(r.dept_id) === divVal || (r.department_code || '').toUpperCase() === divVal.toUpperCase() || (r.department_name || '').toLowerCase().includes(divVal.toLowerCase()));
  renderPRTable(data);
}

async function loadRFQ() {
  try {
    // Always ensure PR data is loaded so we can show quantity/unit from linked PRs
    if (!cachedPR || cachedPR.length === 0) {
      try { cachedPR = await apiRequest('/pr?_cache_bust=' + Date.now()); } catch(e) { console.log('Could not pre-load PRs for RFQ'); }
    }
    // 🔄 FRESH FETCH FROM DATABASE - Cache busting parameter ensures no caching
    const rfq = await apiRequest('/rfq?_cache_bust=' + Date.now());
    console.log('[RFQ] ✅ Fresh data fetched from database');
    cachedRFQ = rfq;
    filterRFQTable();
    return rfq;
  } catch (err) {
    console.log('Using demo RFQ data');
    return [];
  }
}
function filterRFQTable() {
  const statusVal = document.getElementById('rfqStatusFilter')?.value || '';
  let data = cachedRFQ;
  // Draft visibility: admin/hope see all drafts, others only see their own
  if (!userHasAnyRole(['admin', 'hope'])) {
    data = data.filter(r => r.status !== 'draft' || String(r.created_by) === String(currentUser.id));
  }
  // Division filtering: admin/hope see all, others see only their division
  const rfqSeeAllRoles = ['admin', 'hope'];
  if (!userHasAnyRole(rfqSeeAllRoles)) {
    const chiefDivCodeMap = { chief_fad: 'FAD', chief_wrsd: 'WRSD', chief_mwpsd: 'MWPSD', chief_mwptd: 'MWPTD' };
    const chiefRole = getUserChiefRole();
    const userDeptCode = chiefRole ? chiefDivCodeMap[chiefRole] : (currentUser.department_code || currentUser.division || '');
    const userDeptId = currentUser.dept_id;
    if (userDeptCode || userDeptId) {
      data = data.filter(r => (userDeptId && String(r.pr_dept_id) === String(userDeptId)) || (userDeptCode && (r.department_code || '').toUpperCase() === userDeptCode.toUpperCase()));
    }
  }
  if (statusVal) data = data.filter(r => r.status === statusVal);
  renderRFQTable(data);
}

