            <option value="HIGHEST RATED AND RESPONSIVE (HRRB)" ${b.bidder_type === 'HIGHEST RATED AND RESPONSIVE (HRRB)' ? 'selected' : ''}>HIGHEST RATED AND RESPONSIVE (HRRB)</option>
