  window.removePAP = async function(papId, papName) {
    if (!confirm(`Are you sure you want to remove PAP "${papName}"?`)) return;
    try {
      await apiRequest('/paps/' + papId, 'DELETE');
      alert('PAP removed.');
      loadPAPs();
    } catch (err) {
      alert('Error removing PAP: ' + err.message);
    }
  };

